{
  "experiment_plan": {
    "what_to_compare": "英国（MCS, YRBS）および米国（MTF）の青少年データにおいて、デジタルテクノロジー利用量の高低と幸福感（well-being）の複数指標の関連を、事前に定義した多数の分析仕様間で比較する。比較軸は、(1) 利用量の測定法、(2) 幸福感指標、(3) 共変量調整セット、(4) サンプル制限、(5) モデル仕様、(6) 層別化の有無とする。",
    "what_to_measure": "各分析仕様ごとの推定係数の符号、効果量、信頼区間、p値、仕様全体における係数分布、符号反転率、主要アウトカム・主要サンプルでの再現性、ならびにサブグループ別推定値（年齢層、性別、国別）。",
    "procedure": "1) 事前に仕様空間を固定する。2) 各データセットで、利用量の高低を表す複数の定義と幸福感の複数指標を組み合わせ、共変量調整やサンプル制限を変えた仕様を網羅的に推定する。3) 各仕様で関連の方向と大きさを記録する。4) 主要アウトカム・主要サンプルを先に定義し、その結果を優先的に評価する。5) 全仕様の係数分布、符号反転頻度、主要仕様での再現性、サブグループ別の一貫性を確認する。6) 事前に定義した判定規則に従い、各仮説を独立または排他的に判定する。",
    "decision_rule": "H1とH2は排他的関係として扱う。H1は『広い仕様空間で負の関連が安定して再現される』場合に支持し、H2は『仕様変更により符号反転が頻繁に起こる』場合に支持する。H3は独立に判定し、全体平均がほぼゼロであることと、特定のサブグループまたは特定の幸福感指標でのみ系統的な偏りがあることを要件とする。主要アウトカム・主要サンプルの結果を最優先し、その後に仕様全体の分布で補強する。主要結果が判定閾値の境界にある場合は hold とする。",
    "checks": [
      "主要アウトカム定義が事前登録された幸福感指標に一致しているか",
      "主要サンプルが英国・米国の事前定義された対象年齢層に一致しているか",
      "利用量の測定法が極端な欠測や再コード化に依存していないか",
      "仕様空間の探索が事前に定義した範囲を超えていないか",
      "符号反転が特定の単一仕様にのみ依存していないか",
      "サブグループ差がサンプルサイズ不足による偶然ではないか",
      "国別・データセット別の結果が同方向かどうか"
    ],
    "check_targets": [
      {
        "check": "主要アウトカムと主要サンプルでの負の関連の再現性",
        "targets": ["H1", "H2"],
        "if_positive": "主要アウトカム・主要サンプルで負の関連が再現され、かつ仕様全体でも符号が概ね負に集中するならH1を支持し、H2は棄却方向。",
        "if_negative": "主要アウトカム・主要サンプルで負の関連が再現されず、仕様全体で符号反転が頻繁ならH2を支持し、H1は棄却方向。"
      },
      {
        "check": "仕様全体での符号反転頻度",
        "targets": ["H1", "H2"],
        "if_positive": "符号反転が稀で、ほとんどの仕様で負ならH1を支持。",
        "if_negative": "負・ゼロ・正が広く混在し、反転が頻繁ならH2を支持。"
      },
      {
        "check": "サブグループ別の局所的偏り",
        "targets": ["H3"],
        "if_positive": "全体平均はほぼゼロだが、年齢層・性別・国・幸福感指標の一部で系統的な非ゼロ関連があるならH3を支持。",
        "if_negative": "どの主要サブグループでも関連がほぼゼロで、局所的な偏りが見られないならH3を棄却方向。"
      }
    ],
    "hypothesis_rules": [
      {
        "id": "H1",
